    "hammer_artisan.png" = "https://images.steamusercontent.com/ugc/14334913603726867930/8D20EDC162D71133B84153997810D281BBAD6CE6/"
    "hand_lotion.png" = "https://images.steamusercontent.com/ugc/9825948804105677904/03EC8AD975BBED4C1E783AFC2B497FAB10270582/"
    "helium_canister.png" = "https://images.steamusercontent.com/ugc/13617511643142304688/97EB25FF859EB81A742F6F440A0BCD2B9D924FB6/"
}

Write-Host "Downloading $($icons.Count) icons to $outDir..."
$i = 0
foreach ($entry in $icons.GetEnumerator()) {
    $i++
    $outFile = Join-Path $outDir $entry.Key
    if (Test-Path $outFile) {
        Write-Host "[$i/$($icons.Count)] SKIP $($entry.Key) (exists)"
        continue
    }
    try {
        Invoke-WebRequest -Uri $entry.Value -OutFile $outFile -UseBasicParsing
        Write-Host "[$i/$($icons.Count)] OK   $($entry.Key)"
    } catch {
        Write-Host "[$i/$($icons.Count)] FAIL $($entry.Key): $_"
    }
}
Write-Host "Done! Downloaded to $outDir"
